SWEP.Base="arccw_base"SWEP.Spawnable=true SWEP.Category="ArcCW - BlackMod"SWEP.AdminOnly=false SWEP.PrintName="13mm T-Gewehr"SWEP.TrueName="Mauser 1918 Tankgewehr"SWEP.Trivia_Class="Anti-Tank Rifle"SWEP.Trivia_Desc="The world\'s first anti-tank rifle — the first rifle designed for the sole purpose of destroying armoured targets — and the only anti-tank rifle to see service in World War I. Single-shot bolt action based off a modified Mauser bolt-action system, it fires the 13.2×92mm SR, also known as Mauser 13.2mm TuF (German: Tank und Flieger; literally \"tank and aircraft\").\nBoth rifle and ammo were designed to counter early British tanks that appeared in late WWI. The round produces tremendous recoil, and because the rifle itself has no method of reducing recoil, it is designed to be fired from a static position. The makers of this rifle, Mauser, were inspired by the designs of Elephant Guns. The iron sights are composed of a front blade and tangent rear, graduated in 100-meter increments from 100 to 500 meters.\nThe 13.2mm bullets are armour-piercing with a hardened steel core and with a semi rimmed shell, originally designed to be fired from the Maxim MG.18 water-cooled heavy machine gun. The rounds weighed 51.5 g (795 gn) with an initial velocity of 785 m/s (2,580 ft/s).\n"SWEP.Trivia_Manufacturer="Mauser"SWEP.Trivia_Calibre="13.2×92mm SR"SWEP.Trivia_Mechanism="Single-Shot Bolt Action"SWEP.Trivia_Country="German Empire"SWEP.Trivia_Year=1918 SWEP.Slot=3 if(GetConVar("arccw_truenames")):GetBool()then SWEP.PrintName=SWEP.TrueName end SWEP.UseHands=true SWEP.ViewModel="models/weapons/tankgewehr/v_verdun_tankgewehr1918.mdl"SWEP.WorldModel="models/weapons/tankgewehr/w_verdun_tankgewehr.mdl"SWEP.WorldModelOffset={pos=Vector(-2,.75,.55),ang=Angle(-10,0,180);bone="ValveBiped.Bip01_R_Hand";scale=1.2}SWEP.ViewModelFOV=90 SWEP.Damage=350 SWEP.DamageMin=400 SWEP.Range=64 SWEP.RangeMin=32 SWEP.Penetration=200 SWEP.DamageType=DMG_BULLET+DMG_AIRBOAT SWEP.ShootEntity=nil SWEP.MuzzleVelocity=670 SWEP.ChamberSize=0 SWEP.Primary.ClipSize=1 SWEP.ExtendedClipSize=1 SWEP.ReducedClipSize=1 SWEP.Recoil=10 SWEP.RecoilSide=5 SWEP.MaxRecoilBlowback=5 SWEP.Delay=.3 SWEP.Num=1 SWEP.Firemodes={{PrintName="Bolt Action",Mode=1},{PrintName="Lowered",Mode=0}}SWEP.NPCWeaponType={"weapon_ar2";"weapon_crossbow"}SWEP.NPCWeight=1 SWEP.AccuracyMOA=1 SWEP.HipDispersion=800 SWEP.MoveDispersion=200 SWEP.Primary.Ammo="SniperPenetratedRound"SWEP.MagID="tankgewehr"SWEP.ShootVol=160 SWEP.ShootPitch=100 SWEP.ShootSound="tankgewehr.fire"SWEP.ShootSoundSilenced="tankgewehr.fire"SWEP.DistantShootSound="tankgewehr.fire_distant"SWEP.MuzzleEffect="muzzleflash_5"SWEP.ShellModel="models/shells/shell_338mag.mdl"SWEP.ShellPitch=60 SWEP.ShellScale=3 SWEP.ShellEjectPosCorrection=Vector(0,0,0)SWEP.MuzzleEffectAttachment=1 SWEP.CaseEffectAttachment=2 SWEP.SightTime=1.3 SWEP.SpeedMult=.575 SWEP.SightedSpeedMult=.45 SWEP.BulletBones={}SWEP.ProceduralRegularFire=false SWEP.ProceduralIronFire=false SWEP.CaseBones={}SWEP.IronSightStruct={Pos=Vector(-2.8,-2,1.05),Ang=Angle(0,0,0),Magnification=1.1}SWEP.HoldtypeHolstered="passive"SWEP.HoldtypeActive="ar2"SWEP.HoldtypeSights="rpg"SWEP.AnimShoot=ACT_HL2MP_GESTURE_RANGE_ATTACK_RPG SWEP.ActivePos=Vector(0,-4,1)SWEP.ActiveAng=Angle(0,0,0)SWEP.SprintPos=Vector(0,0,2)SWEP.SprintAng=Angle(0,-10,0)SWEP.HolsterPos=Vector(6,-3,0)SWEP.HolsterAng=Angle(-7,40,0)SWEP.CrouchPos=Vector(-1,-3,0)SWEP.CrouchAng=Angle(0,0,-2)SWEP.BarrelOffsetSighted=Vector(0,0,-1)SWEP.BarrelOffsetHip=Vector(2,0,-2)SWEP.BarrelLength=75 SWEP.ExtraSightDist=5 SWEP.Hook_BulletHit=function(X,R)local O=R.tr.Entity util.BlastDamage(X,X:GetOwner(),R.tr.HitPos,18,X:GetDamage(R.range))if O:IsValid()and O:GetClass()=="npc_helicopter"then R.dmgtype=DMG_AIRBOAT end end SWEP.InBipodPos=Vector(-4,0,0)SWEP.InBipodAng=Angle(0,0,0)SWEP.Bipod_Integral=true SWEP.BipodDispersion=.3 SWEP.BipodRecoil=.3 SWEP.M_Hook_Mult_SightTime=function(X,R)if X:InBipod()then R.mult=1.25 end end SWEP.M_Hook_Mult_